import React, { useState, useRef, useEffect, useMemo } from 'react';
import { ProposalData, Role } from '../types';
import { formatCurrency } from '../utils/pricingEngine';
import { Users, Plus, Trash2, LayoutList, LayoutGrid, CheckSquare, Workflow, Move, ZoomIn, ZoomOut, MousePointer2, X, Link as LinkIcon, Palette, ChevronDown, ChevronUp, Briefcase } from 'lucide-react';

interface TeamProps {
  data: ProposalData;
  updateData: (newData: Partial<ProposalData>) => void;
}

// Cores para personalização dos cards
const CARD_COLORS = [
    { id: 'slate', bg: 'bg-slate-50', border: 'border-slate-200', header: 'bg-slate-100', text: 'text-slate-700' },
    { id: 'blue', bg: 'bg-blue-50', border: 'border-blue-200', header: 'bg-blue-100', text: 'text-blue-700' },
    { id: 'emerald', bg: 'bg-emerald-50', border: 'border-emerald-200', header: 'bg-emerald-100', text: 'text-emerald-700' },
    { id: 'amber', bg: 'bg-amber-50', border: 'border-amber-200', header: 'bg-amber-100', text: 'text-amber-700' },
    { id: 'red', bg: 'bg-red-50', border: 'border-red-200', header: 'bg-red-100', text: 'text-red-700' },
    { id: 'purple', bg: 'bg-purple-50', border: 'border-purple-200', header: 'bg-purple-100', text: 'text-purple-700' },
];

const Team: React.FC<TeamProps> = ({ data, updateData }) => {
  const [viewMode, setViewMode] = useState<'list' | 'grid' | 'organogram'>('list');

  // --- Organogram State ---
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const [isDraggingNode, setIsDraggingNode] = useState<string | null>(null);
  const [connectingNodeId, setConnectingNodeId] = useState<string | null>(null); // ID do nó que está começando a linha
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 }); // Para desenhar a linha temporária
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number, type: 'node' | 'edge' | 'canvas', targetId?: string } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const dragStartRef = useRef({ x: 0, y: 0 });

  // --- Logic for Roles ---
  const addRole = (category: 'Operational' | 'Administrative', startX?: number, startY?: number) => {
    // Se coordenadas não forem passadas, centraliza na tela atual
    const defaultX = -pan.x + (window.innerWidth / 2) - 128; // Center - half card width
    const defaultY = -pan.y + (window.innerHeight / 2) - 100;

    const newRole: Role = {
      id: Math.random().toString(36).substr(2, 9),
      title: category === 'Operational' ? 'Novo Técnico' : 'Novo Analista',
      category,
      quantity: 1,
      baseSalary: 2000,
      additionalHazard: category === 'Operational',
      additionalDanger: false,
      // Posição padrão para o organograma
      x: (startX ?? defaultX) / scale,
      y: (startY ?? defaultY) / scale,
      color: 'slate'
    };
    updateData({ roles: [...data.roles, newRole] });
  };

  const updateRole = (id: string, field: keyof Role, value: any) => {
    const updatedRoles = data.roles.map(r => r.id === id ? { ...r, [field]: value } : r);
    updateData({ roles: updatedRoles });
  };

  const removeRole = (id: string) => {
    if (confirm('Remover este cargo?')) {
        // Remove role and any connections where this role is the parent
        const updatedRoles = data.roles
            .filter(r => r.id !== id)
            .map(r => r.parentId === id ? { ...r, parentId: undefined } : r);
        updateData({ roles: updatedRoles });
    }
  };

  const calculateRoleCost = (role: Role) => {
     let base = role.baseSalary;
     let addOns = 0;
     if (role.additionalHazard) addOns += role.baseSalary * 0.20;
     if (role.additionalDanger) addOns += role.baseSalary * 0.30;
     const totalBase = base + addOns;
     const charges = totalBase * data.taxConfig.socialChargesRate;
     return (totalBase + charges) * role.quantity;
  };

  // --- Canvas Event Handlers ---

  const handleMouseDown = (e: React.MouseEvent) => {
    // Middle mouse or Space+Click or Alt+Click to Pan
    if (e.button === 1 || (e.button === 0 && e.altKey)) {
        setIsPanning(true);
        dragStartRef.current = { x: e.clientX - pan.x, y: e.clientY - pan.y };
        e.preventDefault();
        return;
    }

    // Close context menu on left click
    if (e.button === 0) setContextMenu(null);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
      // Update global mouse pos for connection line drawing relative to canvas
      if (canvasRef.current) {
          const rect = canvasRef.current.getBoundingClientRect();
          // Adjust for pan and scale to get "world" coordinates
          setMousePos({
              x: (e.clientX - rect.left - pan.x) / scale,
              y: (e.clientY - rect.top - pan.y) / scale
          });
      }

      if (isPanning) {
          setPan({
              x: e.clientX - dragStartRef.current.x,
              y: e.clientY - dragStartRef.current.y
          });
      }

      if (isDraggingNode && !isPanning) {
          // Calculate delta in screen pixels
          const screenDeltaX = e.clientX - dragStartRef.current.x;
          const screenDeltaY = e.clientY - dragStartRef.current.y;

          // Apply new position
          const node = data.roles.find(r => r.id === isDraggingNode);
          if (node && node.x !== undefined && node.y !== undefined) {
             // We need to update based on the *initial* drag position, 
             // but simpler is just setting absolute pos if we tracked the offset properly.
             // Here we use a simpler approach: update absolute pos
             // Re-calculate dragStartRef each frame to act as 'previous mouse pos'

             // Better Approach: 
             // 1. Get current mouse in world coords
             // 2. Set node x/y to mouse world coords minus offset

             // Simplest for now:
             const dx = e.movementX / scale;
             const dy = e.movementY / scale;

             updateRole(isDraggingNode, 'x', (node.x || 0) + dx);
             updateRole(isDraggingNode, 'y', (node.y || 0) + dy);
          }
      }
  };

  const handleMouseUp = () => {
      setIsPanning(false);
      setIsDraggingNode(null);
      // Se soltar o mouse enquanto conecta, cancela se não acertou um node
      if (connectingNodeId) {
          setConnectingNodeId(null);
      }
  };

  const handleWheel = (e: React.WheelEvent) => {
      if (e.ctrlKey || e.metaKey) {
          e.preventDefault();
          const zoomSensitivity = 0.001;
          const newScale = Math.min(Math.max(0.1, scale - e.deltaY * zoomSensitivity), 3);

          // Optional: Zoom towards mouse pointer logic could go here
          setScale(newScale);
      } else {
          // Normal scroll pans
          setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
      }
  };

  // --- Node Events ---
  const onNodeDragStart = (e: React.MouseEvent, id: string) => {
      if (e.button !== 0 || e.altKey || connectingNodeId) return; 
      e.stopPropagation();
      setIsDraggingNode(id);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
  };

  const onConnectorMouseDown = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      e.preventDefault(); // Prevent text selection
      setConnectingNodeId(id);
  };

  const onNodeMouseUp = (e: React.MouseEvent, targetId: string) => {
      e.stopPropagation();
      if (connectingNodeId && connectingNodeId !== targetId) {
          // Check for cycles? (Simple check: direct parent)
          const targetNode = data.roles.find(r => r.id === targetId);
          if (targetNode?.parentId !== connectingNodeId) {
             updateRole(targetId, 'parentId', connectingNodeId);
          }
      }
      setConnectingNodeId(null);
  };

  const handleContextMenuCanvas = (e: React.MouseEvent, type: 'node' | 'edge' | 'canvas', targetId?: string) => {
      e.preventDefault();
      e.stopPropagation();
      setContextMenu({
          x: e.clientX,
          y: e.clientY,
          type,
          targetId
      });
  };

  // --- Drawing Helpers ---
  const getCurvePath = (x1: number, y1: number, x2: number, y2: number) => {
    const dist = Math.abs(y2 - y1) * 0.5;
    const cp1x = x1;
    const cp1y = y1 + Math.max(50, dist);
    const cp2x = x2;
    const cp2y = y2 - Math.max(50, dist);
    return `M ${x1} ${y1} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${x2} ${y2}`;
  };

  // --- Context Menu Actions ---
  const setNodeColor = (colorId: string) => {
      if (contextMenu?.targetId) updateRole(contextMenu.targetId, 'color', colorId);
      setContextMenu(null);
  };

  const disconnectParent = () => {
      if (contextMenu?.targetId) updateRole(contextMenu.targetId, 'parentId', undefined);
      setContextMenu(null);
  };

  const deleteNode = () => {
      if (contextMenu?.targetId) removeRole(contextMenu.targetId);
      setContextMenu(null);
  };

  const handleAddRoleFromContext = (category: 'Operational' | 'Administrative') => {
      if (contextMenu && canvasRef.current) {
          const rect = canvasRef.current.getBoundingClientRect();
          const x = contextMenu.x - rect.left - pan.x;
          const y = contextMenu.y - rect.top - pan.y;
          addRole(category, x, y);
      }
      setContextMenu(null);
  };

  // --- Initial Position Init ---
  useEffect(() => {
      if (viewMode === 'organogram') {
          // Initialize coordinates for nodes that don't have them
          const needsInit = data.roles.some(r => r.x === undefined);
          if (needsInit) {
              const updatedRoles = data.roles.map((r, i) => ({
                  ...r,
                  x: r.x ?? (i * 280) % 1000,
                  y: r.y ?? Math.floor(i / 4) * 200,
                  color: r.color ?? 'slate'
              }));
              updateData({ roles: updatedRoles });
          }
      }
  }, [viewMode]);

  const roles = data.roles;

  return (
    <div className="flex flex-col h-full overflow-hidden">
      {/* Header Toolbar */}
      <div className="p-8 pb-4 shrink-0 max-w-[1600px] mx-auto w-full">
          <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-slate-200 pb-6">
            <div>
              <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
                {viewMode === 'organogram' ? <Workflow size={28} className="text-[#0f172a]" /> : <Users size={28} className="text-[#0f172a]" />}
                Quadro de Pessoal
              </h2>
              <p className="text-slate-500 text-sm mt-1">
                  {viewMode === 'organogram' 
                    ? 'Editor visual de hierarquia. Arraste para conectar e organizar.' 
                    : 'Definição de cargos, salários e adicionais trabalhistas.'}
              </p>
            </div>

            <div className="flex gap-4">
                {viewMode === 'organogram' && (
                    <div className="flex bg-white border border-slate-200 rounded-lg p-1 shadow-sm items-center">
                        <button onClick={() => setScale(s => Math.max(0.2, s - 0.1))} className="p-2 hover:bg-slate-50 text-slate-500 rounded"><ZoomOut size={16}/></button>
                        <span className="text-xs font-mono font-bold w-12 text-center">{Math.round(scale * 100)}%</span>
                        <button onClick={() => setScale(s => Math.min(3, s + 0.1))} className="p-2 hover:bg-slate-50 text-slate-500 rounded"><ZoomIn size={16}/></button>
                        <div className="w-px h-4 bg-slate-200 mx-2"></div>
                        <div className="flex items-center gap-2 px-2 text-[10px] text-slate-400 font-medium">
                            <Move size={12} /> Alt + Drag
                        </div>
                    </div>
                )}

                <div className="flex bg-slate-100 p-1 rounded-lg">
                    <button 
                    onClick={() => setViewMode('list')}
                    className={`p-2 rounded-md transition-all ${viewMode === 'list' ? 'bg-white text-[#0f172a] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                    title="Lista"
                    >
                    <LayoutList size={20} />
                    </button>
                    <button 
                    onClick={() => setViewMode('grid')}
                    className={`p-2 rounded-md transition-all ${viewMode === 'grid' ? 'bg-white text-[#0f172a] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                    title="Cards"
                    >
                    <LayoutGrid size={20} />
                    </button>
                    <button 
                    onClick={() => setViewMode('organogram')}
                    className={`p-2 rounded-md transition-all ${viewMode === 'organogram' ? 'bg-white text-[#0f172a] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                    title="Organograma"
                    >
                    <Workflow size={20} />
                    </button>
                </div>
            </div>
          </header>
      </div>

      {/* VIEW CONTENT */}
      {viewMode === 'organogram' ? (
        <div className="flex-1 relative bg-slate-50 overflow-hidden cursor-grab active:cursor-grabbing border-t border-slate-200 select-none">
            {/* Background Pattern */}
            <div 
                className="absolute inset-0 opacity-[0.03] pointer-events-none"
                style={{
                    backgroundImage: 'radial-gradient(#0f172a 1px, transparent 1px)',
                    backgroundSize: `${20 * scale}px ${20 * scale}px`,
                    backgroundPosition: `${pan.x}px ${pan.y}px`
                }}
            />

            {/* Canvas Container */}
            <div 
                ref={canvasRef}
                className="absolute inset-0 w-full h-full"
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={handleMouseUp}
                onWheel={handleWheel}
                onContextMenu={(e) => handleContextMenuCanvas(e, 'canvas')}
            >
                <div 
                    className="absolute top-0 left-0 w-full h-full origin-top-left"
                    style={{ 
                        transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
                    }}
                >
                    {/* LAYER 1: CONNECTIONS (SVG) */}
                    <svg className="absolute top-[-5000px] left-[-5000px] w-[10000px] h-[10000px] pointer-events-none overflow-visible">
                        <defs>
                            <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
                                <polygon points="0 0, 10 3.5, 0 7" fill="#94a3b8" />
                            </marker>
                            <marker id="arrowhead-active" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
                                <polygon points="0 0, 10 3.5, 0 7" fill="#fbbf24" />
                            </marker>
                        </defs>

                        {roles.map(role => {
                            if (!role.parentId) return null;
                            const parent = roles.find(r => r.id === role.parentId);
                            if (!parent) return null;

                            // Coordinates
                            const pX = (parent.x || 0) + 128; // Center of card (width 256)
                            const pY = (parent.y || 0) + 140; // Bottom of card (approx height)
                            const cX = (role.x || 0) + 128;
                            const cY = (role.y || 0);

                            const path = getCurvePath(pX, pY, cX, cY);

                            return (
                                <g key={`link-${role.id}`} className="pointer-events-auto">
                                    {/* Thick invisible path for easier clicking */}
                                    <path d={path} stroke="transparent" strokeWidth="20" fill="none" 
                                          onContextMenu={(e) => handleContextMenuCanvas(e, 'edge', role.id)}
                                          className="cursor-pointer hover:stroke-black/5 transition-colors"
                                    />
                                    {/* Visible Path */}
                                    <path d={path} stroke="#94a3b8" strokeWidth="2" fill="none" markerEnd="url(#arrowhead)" />
                                </g>
                            )
                        })}

                        {/* Temporary Drawing Line */}
                        {connectingNodeId && (
                            <path 
                                d={(() => {
                                    const source = roles.find(r => r.id === connectingNodeId);
                                    if (!source) return '';
                                    const sX = (source.x || 0) + 128;
                                    const sY = (source.y || 0) + 140;
                                    return getCurvePath(sX, sY, mousePos.x, mousePos.y);
                                })()}
                                stroke="#fbbf24" strokeWidth="2" strokeDasharray="5,5" fill="none" markerEnd="url(#arrowhead-active)"
                            />
                        )}
                    </svg>

                    {/* LAYER 2: NODES (HTML) */}
                    {roles.map(role => {
                        const style = CARD_COLORS.find(c => c.id === (role.color || 'slate')) || CARD_COLORS[0];

                        return (
                            <div 
                                key={role.id}
                                className={`absolute w-64 bg-white rounded-xl shadow-sm border hover:shadow-xl transition-shadow ${style.border} ${connectingNodeId === role.id ? 'ring-2 ring-[#fbbf24]' : ''}`}
                                style={{ 
                                    left: role.x || 0, 
                                    top: role.y || 0,
                                }}
                                onContextMenu={(e) => handleContextMenuCanvas(e, 'node', role.id)}
                                onMouseUp={(e) => onNodeMouseUp(e, role.id)}
                            >
                                {/* Input Connector (Top) */}
                                <div 
                                    className="absolute -top-3 left-1/2 -translate-x-1/2 w-6 h-6 rounded-full bg-white border border-slate-300 shadow-sm flex items-center justify-center cursor-crosshair hover:border-blue-500 hover:bg-blue-50 z-20 group/conn"
                                    onMouseUp={(e) => onNodeMouseUp(e, role.id)}
                                >
                                    <div className="w-2 h-2 rounded-full bg-slate-300 group-hover/conn:bg-blue-500 transition-colors"></div>
                                </div>

                                {/* Header (Drag Handle) */}
                                <div 
                                    className={`p-3 rounded-t-xl border-b cursor-grab active:cursor-grabbing flex justify-between items-center ${style.header} ${style.border}`}
                                    onMouseDown={(e) => onNodeDragStart(e, role.id)}
                                >
                                    <div className="flex items-center gap-2">
                                        <div className={`p-1 bg-white/50 rounded ${style.text}`}>
                                            {role.category === 'Operational' ? <Briefcase size={14}/> : <CheckSquare size={14}/>}
                                        </div>
                                        <span className={`text-xs font-bold uppercase tracking-wider ${style.text}`}>{role.category === 'Operational' ? 'Operacional' : 'Admin'}</span>
                                    </div>
                                </div>

                                {/* Body */}
                                <div className="p-3">
                                    <input 
                                        type="text" 
                                        value={role.title}
                                        onChange={(e) => updateRole(role.id, 'title', e.target.value)}
                                        className="w-full font-bold text-slate-800 bg-transparent border-none p-0 focus:ring-0 text-sm mb-2"
                                        placeholder="Nome do Cargo"
                                    />

                                    <div className="grid grid-cols-2 gap-2 mb-2">
                                        <div>
                                            <label className="text-[9px] font-bold text-slate-400 uppercase">Salário</label>
                                            <div className="flex items-center bg-slate-50 rounded px-2 py-1 border border-slate-100">
                                                <span className="text-[10px] text-slate-400 mr-1">R$</span>
                                                <input 
                                                    type="number"
                                                    value={role.baseSalary}
                                                    onChange={(e) => updateRole(role.id, 'baseSalary', parseFloat(e.target.value))}
                                                    className="w-full bg-transparent text-xs font-bold text-slate-700 p-0 border-none focus:ring-0"
                                                />
                                            </div>
                                        </div>
                                        <div>
                                            <label className="text-[9px] font-bold text-slate-400 uppercase">Qtd</label>
                                            <input 
                                                type="number"
                                                value={role.quantity}
                                                onChange={(e) => updateRole(role.id, 'quantity', parseFloat(e.target.value))}
                                                className="w-full bg-slate-50 text-xs font-bold text-slate-700 px-2 py-1 rounded border border-slate-100 focus:ring-0 focus:border-blue-300 text-center"
                                            />
                                        </div>
                                    </div>

                                    <div className="flex justify-between items-center text-[10px] text-slate-400 border-t border-slate-100 pt-2">
                                        <span>Total: {formatCurrency(calculateRoleCost(role))}</span>
                                    </div>
                                </div>

                                {/* Output Connector (Bottom) */}
                                <div 
                                    className="absolute -bottom-3 left-1/2 -translate-x-1/2 w-6 h-6 rounded-full bg-white border border-slate-300 shadow-sm flex items-center justify-center cursor-crosshair hover:border-amber-500 hover:bg-amber-50 z-20 group/conn"
                                    onMouseDown={(e) => onConnectorMouseDown(e, role.id)}
                                >
                                    <div className="w-2 h-2 rounded-full bg-slate-300 group-hover/conn:bg-amber-500 transition-colors"></div>
                                </div>
                            </div>
                        )
                    })}
                </div>
            </div>

            {/* Context Menu */}
            {contextMenu && (
                <div 
                    className="fixed z-50 bg-white rounded-lg shadow-xl border border-slate-200 py-1 w-48 text-sm animate-in fade-in zoom-in-95 duration-100"
                    style={{ top: contextMenu.y, left: contextMenu.x }}
                    onClick={(e) => e.stopPropagation()} // Prevent click from closing immediately via canvas handler
                >
                    {contextMenu.type === 'node' && (
                        <>
                            <div className="px-3 py-1.5 text-[10px] font-bold text-slate-400 uppercase tracking-wider border-b border-slate-100 mb-1">
                                Opções do Cargo
                            </div>
                            <button onClick={disconnectParent} className="w-full text-left px-4 py-2 hover:bg-slate-50 text-slate-700 flex items-center gap-2">
                                <LinkIcon size={14} className="text-slate-400"/> Desconectar
                            </button>

                            <div className="px-4 py-2 hover:bg-slate-50 flex items-center gap-2 relative group/colors">
                                <Palette size={14} className="text-slate-400"/> 
                                <span className="text-slate-700">Cor do Card</span>
                                <div className="absolute left-full top-0 ml-1 bg-white border border-slate-200 shadow-lg rounded-lg p-2 grid grid-cols-3 gap-1 hidden group-hover/colors:grid">
