                    )}

                    {contextMenu.type === 'edge' && (
                        <button onClick={disconnectParent} className="w-full text-left px-4 py-2 hover:bg-red-50 text-red-600 flex items-center gap-2">
                            <Trash2 size={14}/> Remover Conexão
                        </button>
                    )}

                    {contextMenu.type === 'canvas' && (
                        <>
                             <div className="px-3 py-1.5 text-[10px] font-bold text-slate-400 uppercase tracking-wider border-b border-slate-100 mb-1">
                                Ações do Quadro
                            </div>
                            <button onClick={() => handleAddRoleFromContext('Operational')} className="w-full text-left px-4 py-2 hover:bg-slate-50 text-slate-700 flex items-center gap-2">
                                <Plus size={14} className="text-blue-500"/> Novo Operacional
                            </button>
                            <button onClick={() => handleAddRoleFromContext('Administrative')} className="w-full text-left px-4 py-2 hover:bg-slate-50 text-slate-700 flex items-center gap-2">
                                <Plus size={14} className="text-purple-500"/> Novo Administrativo
                            </button>
                            <div className="h-px bg-slate-100 my-1"></div>
                            <button onClick={() => { setScale(1); setPan({x:0, y:0}); setContextMenu(null); }} className="w-full text-left px-4 py-2 hover:bg-slate-50 text-slate-700 flex items-center gap-2">
                                <Move size={14} className="text-slate-400"/> Centralizar Visão
                            </button>
                        </>
                    )}
                </div>
            )}
        </div>
      ) : (
          /* LIST OR GRID VIEW (Standard Implementation) */
          <div className="p-8 max-w-[1600px] mx-auto w-full">
            {viewMode === 'list' && (
               <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                  <table className="w-full text-sm text-left">
                     <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-xs tracking-wider border-b border-slate-200">
