    { id: 'red', bg: 'bg-red-50', border: 'border-red-200', header: 'bg-red-100', text: 'text-red-700' },
    { id: 'purple', bg: 'bg-purple-50', border: 'border-purple-200', header: 'bg-purple-100', text: 'text-purple-700' },
    { id: 'dark', bg: 'bg-[#1e293b]', border: 'border-slate-600', header: 'bg-[#0f172a]', text: 'text-white' },
];

const SECTION_COLORS = [
    { id: 'gray', bg: 'bg-slate-100/50', border: 'border-slate-300' },
    { id: 'blue', bg: 'bg-blue-100/30', border: 'border-blue-200' },
    { id: 'green', bg: 'bg-emerald-100/30', border: 'border-emerald-200' },
    { id: 'yellow', bg: 'bg-amber-100/30', border: 'border-amber-200' },
];

const Team: React.FC<TeamProps> = ({ data, updateData }) => {
  const [viewMode, setViewMode] = useState<'list' | 'grid' | 'organogram'>('list');

  // --- Organogram State ---
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);

  // Generic Drag State for Roles, Sections, Decorations
  const [draggingItem, setDraggingItem] = useState<{
      type: 'role' | 'section' | 'decoration' | 'resize-section';
      id: string;
      startX: number;
      startY: number;
      initialObjX: number;
      initialObjY: number;
      initialObjW?: number; // for resize
      initialObjH?: number; // for resize
  } | null>(null);

  const [connectingNodeId, setConnectingNodeId] = useState<string | null>(null); // ID do nó que está começando a linha
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 }); // Para desenhar a linha temporária
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number, type: 'node' | 'section' | 'decoration' | 'canvas', targetId?: string } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);

  // --- Actions ---

  const addRole = (category: 'Operational' | 'Administrative', startX?: number, startY?: number) => {
    const defaultX = -pan.x + (window.innerWidth / 2) - 128;
    const defaultY = -pan.y + (window.innerHeight / 2) - 100;

    const newRole: Role = {
      id: Math.random().toString(36).substr(2, 9),
      title: category === 'Operational' ? 'Novo Técnico' : 'Analista',
      category,
      quantity: 1,
      baseSalary: 2000,
      additionalHazard: category === 'Operational',
      additionalDanger: false,
      x: (startX ?? defaultX) / scale,
      y: (startY ?? defaultY) / scale,
      color: 'slate'
    };
    updateData({ roles: [...data.roles, newRole] });
  };

  const addSection = (x: number, y: number) => {
      const newSection: CanvasSection = {
          id: Math.random().toString(36).substr(2, 9),
          title: 'Nova Área',
          x: x / scale,
          y: y / scale,
          width: 400,
          height: 300,
          color: 'gray'
      };
      updateData({ sections: [...(data.sections || []), newSection] });
  };

  const addDecoration = (type: CanvasDecoration['type'], x: number, y: number) => {
      const newDeco: CanvasDecoration = {
          id: Math.random().toString(36).substr(2, 9),
          type,
          x: x / scale,
          y: y / scale,
          scale: 1,
          label: ''
      };
      updateData({ decorations: [...(data.decorations || []), newDeco] });
  };

  const duplicateRole = (roleId: string) => {
      const source = data.roles.find(r => r.id === roleId);
      if(!source) return;
      const newRole = {
          ...source,
          id: Math.random().toString(36).substr(2, 9),
          x: (source.x || 0) + 20,
          y: (source.y || 0) + 20,
          parentId: source.parentId // Maintain parent connection? Maybe.
      };
      updateData({ roles: [...data.roles, newRole] });
  };

  const updateRole = (id: string, field: keyof Role, value: any) => {
    updateData({ roles: data.roles.map(r => r.id === id ? { ...r, [field]: value } : r) });
  };

  const updateSection = (id: string, field: keyof CanvasSection, value: any) => {
      const sections = data.sections || [];
      updateData({ sections: sections.map(s => s.id === id ? { ...s, [field]: value } : s) });
  };

  const removeEntity = (type: 'role' | 'section' | 'decoration', id: string) => {
    if(type === 'role') {
        const updatedRoles = data.roles
            .filter(r => r.id !== id)
            .map(r => r.parentId === id ? { ...r, parentId: undefined } : r);
        updateData({ roles: updatedRoles });
    }
    if(type === 'section') {
        updateData({ sections: (data.sections || []).filter(s => s.id !== id) });
    }
    if(type === 'decoration') {
        updateData({ decorations: (data.decorations || []).filter(d => d.id !== id) });
    }
  };

  const calculateRoleCost = (role: Role) => {
     let base = role.baseSalary;
     let addOns = 0;
     if (role.additionalHazard) addOns += role.baseSalary * 0.20;
     if (role.additionalDanger) addOns += role.baseSalary * 0.30;
     const totalBase = base + addOns;
     const charges = totalBase * data.taxConfig.socialChargesRate;
     return (totalBase + charges) * role.quantity;
  };

  // --- Canvas Interaction Logic ---

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button === 1 || (e.button === 0 && e.altKey)) {
        setIsPanning(true);
        e.preventDefault();
        return;
    }
    if (e.button === 0) setContextMenu(null);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
      // 1. Update Mouse Pos for Ghost Lines
      if (canvasRef.current) {
          const rect = canvasRef.current.getBoundingClientRect();
          setMousePos({
              x: (e.clientX - rect.left - pan.x) / scale,
              y: (e.clientY - rect.top - pan.y) / scale
          });
      }

      // 2. Pan Background
      if (isPanning) {
          setPan(prev => ({ x: prev.x + e.movementX, y: prev.y + e.movementY }));
          return;
      }

      // 3. Drag Entities (Roles, Sections, Icons)
      if (draggingItem) {
          const deltaX = (e.clientX - draggingItem.startX) / scale;
          const deltaY = (e.clientY - draggingItem.startY) / scale;

          if (draggingItem.type === 'role') {
              updateRole(draggingItem.id, 'x', draggingItem.initialObjX + deltaX);
              updateRole(draggingItem.id, 'y', draggingItem.initialObjY + deltaY);
          } else if (draggingItem.type === 'section') {
              updateSection(draggingItem.id, 'x', draggingItem.initialObjX + deltaX);
              updateSection(draggingItem.id, 'y', draggingItem.initialObjY + deltaY);
          } else if (draggingItem.type === 'decoration') {
              const decos = data.decorations || [];
              const updated = decos.map(d => d.id === draggingItem.id ? { ...d, x: draggingItem.initialObjX + deltaX, y: draggingItem.initialObjY + deltaY } : d);
              updateData({ decorations: updated });
          } else if (draggingItem.type === 'resize-section') {
             updateSection(draggingItem.id, 'width', Math.max(100, (draggingItem.initialObjW || 0) + deltaX));
             updateSection(draggingItem.id, 'height', Math.max(100, (draggingItem.initialObjH || 0) + deltaY));
          }
      }
  };

  const handleMouseUp = () => {
      setIsPanning(false);
      setDraggingItem(null);
      // Connect logic
      if (connectingNodeId) {
          setConnectingNodeId(null);
      }
  };

  const onDragStartEntity = (e: React.MouseEvent, type: 'role' | 'section' | 'decoration' | 'resize-section', id: string, initialObj: any) => {
      if (e.button !== 0 || e.altKey || connectingNodeId) return;
      e.stopPropagation();
      setDraggingItem({
          type,
          id,
          startX: e.clientX,
          startY: e.clientY,
          initialObjX: initialObj.x,
          initialObjY: initialObj.y,
          initialObjW: initialObj.width,
          initialObjH: initialObj.height
      });
  };

  // --- Connection Logic (Smart Routing) ---
  const getNodeCenter = (role: Role) => ({ x: (role.x || 0) + 128, y: (role.y || 0) + 80 }); // approx half width/height
  const getPortPosition = (role: Role, side: 'top' | 'right' | 'bottom' | 'left') => {
      const w = 256; const h = 160;
      const x = role.x || 0; const y = role.y || 0;
      switch(side) {
          case 'top': return { x: x + w/2, y: y };
          case 'right': return { x: x + w, y: y + h/2 };
          case 'bottom': return { x: x + w/2, y: y + h };
          case 'left': return { x: x, y: y + h/2 };
      }
  };

  // Find shortest distance between any port of parent and any port of child
  const getSmartPath = (parent: Role, child: Role) => {
      const sides = ['top', 'right', 'bottom', 'left'] as const;
      let minDist = Infinity;
      let bestStart = getPortPosition(parent, 'bottom');
      let bestEnd = getPortPosition(child, 'top');

      // Simple heuristic: choose ports based on relative position
      const pCenter = getNodeCenter(parent);
      const cCenter = getNodeCenter(child);
      const dx = cCenter.x - pCenter.x;
      const dy = cCenter.y - pCenter.y;

      let startSide: 'top'|'right'|'bottom'|'left' = 'bottom';
      let endSide: 'top'|'right'|'bottom'|'left' = 'top';

      if (Math.abs(dx) > Math.abs(dy)) {
          // Horizontal alignment
          startSide = dx > 0 ? 'right' : 'left';
          endSide = dx > 0 ? 'left' : 'right';
      } else {
          // Vertical alignment
          startSide = dy > 0 ? 'bottom' : 'top';
          endSide = dy > 0 ? 'top' : 'bottom';
      }

      const p1 = getPortPosition(parent, startSide);
      const p2 = getPortPosition(child, endSide);

      // Control Points for smooth Bezier
      const dist = Math.hypot(p2.x - p1.x, p2.y - p1.y) * 0.5;

      let cp1 = { x: p1.x, y: p1.y };
      let cp2 = { x: p2.x, y: p2.y };

      if (startSide === 'right') cp1.x += dist;
      if (startSide === 'left') cp1.x -= dist;
      if (startSide === 'bottom') cp1.y += dist;
      if (startSide === 'top') cp1.y -= dist;

      if (endSide === 'right') cp2.x += dist;
      if (endSide === 'left') cp2.x -= dist;
      if (endSide === 'bottom') cp2.y += dist;
      if (endSide === 'top') cp2.y -= dist;

      return `M ${p1.x} ${p1.y} C ${cp1.x} ${cp1.y}, ${cp2.x} ${cp2.y}, ${p2.x} ${p2.y}`;
  };

  const onConnectorMouseUp = (e: React.MouseEvent, targetId: string) => {
      e.stopPropagation();
      if (connectingNodeId && connectingNodeId !== targetId) {
          updateRole(targetId, 'parentId', connectingNodeId);
      }
      setConnectingNodeId(null);
  };

  // --- Context Menu Handlers ---
  const handleContextMenuCanvas = (e: React.MouseEvent, type: 'node' | 'section' | 'decoration' | 'canvas', targetId?: string) => {
      e.preventDefault();
      e.stopPropagation();
      setContextMenu({ x: e.clientX, y: e.clientY, type, targetId });
  };

  const handleAddEntityAtContext = (type: 'role-op' | 'role-adm' | 'section' | 'deco-factory' | 'deco-truck') => {
      if(!contextMenu || !canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const x = contextMenu.x - rect.left - pan.x;
      const y = contextMenu.y - rect.top - pan.y;

      if(type === 'role-op') addRole('Operational', x, y);
      if(type === 'role-adm') addRole('Administrative', x, y);
      if(type === 'section') addSection(x, y);
      if(type === 'deco-factory') addDecoration('factory', x, y);
      if(type === 'deco-truck') addDecoration('truck', x, y);

      setContextMenu(null);
  };

  // --- Input Mask for Currency ---
  const handleSalaryChange = (id: string, rawValue: string) => {
      // Remove non-numeric
      const numeric = rawValue.replace(/\D/g, '');
      const val = numeric ? parseFloat(numeric) / 100 : 0;
      updateRole(id, 'baseSalary', val);
  };

  // --- Render Helpers ---
  const getDecorationIcon = (type: string) => {
      const size = 32;
      switch(type) {
          case 'factory': return <Factory size={size} />;
          case 'tools': return <Wrench size={size} />;
          case 'truck': return <Truck size={size} />;
          case 'alert': return <AlertTriangle size={size} />;
          case 'box': return <Box size={size} />;
          default: return <Briefcase size={size} />;
      }
  };

  useEffect(() => {
    // Initial Positioning if empty
    if (viewMode === 'organogram' && data.roles.length > 0 && data.roles[0].x === undefined) {
         const updatedRoles = data.roles.map((r, i) => ({
             ...r,
             x: (i % 3) * 300,
             y: Math.floor(i / 3) * 250
         }));
         updateData({ roles: updatedRoles });
    }
  }, [viewMode]);

  const roles = data.roles;
  const sections = data.sections || [];
  const decorations = data.decorations || [];

  return (
    <div className="flex flex-col h-full overflow-hidden">
      {/* Header Toolbar */}
      <div className="p-8 pb-4 shrink-0 max-w-[1600px] mx-auto w-full z-20 relative">
          <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-slate-200 pb-6">
            <div>
              <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
                {viewMode === 'organogram' ? <Workflow size={28} className="text-[#0f172a]" /> : <Users size={28} className="text-[#0f172a]" />}
                Quadro de Pessoal
              </h2>
              <p className="text-slate-500 text-sm mt-1">
                  {viewMode === 'organogram' 
                    ? 'Canvas Interativo: Arraste, conecte e organize a estrutura.' 
                    : 'Definição de cargos, salários e adicionais trabalhistas.'}
              </p>
            </div>

            <div className="flex gap-4">
                {viewMode === 'organogram' && (
                    <div className="flex bg-white border border-slate-200 rounded-lg p-1 shadow-sm items-center">
                        <button onClick={() => addSection(100, 100)} className="p-2 hover:bg-slate-50 text-slate-500 rounded" title="Adicionar Área"><Grip size={16}/></button>
                        <div className="w-px h-4 bg-slate-200 mx-1"></div>
                        <button onClick={() => setScale(s => Math.max(0.2, s - 0.1))} className="p-2 hover:bg-slate-50 text-slate-500 rounded"><ZoomOut size={16}/></button>
                        <span className="text-xs font-mono font-bold w-12 text-center">{Math.round(scale * 100)}%</span>
                        <button onClick={() => setScale(s => Math.min(3, s + 0.1))} className="p-2 hover:bg-slate-50 text-slate-500 rounded"><ZoomIn size={16}/></button>
                    </div>
                )}

                <div className="flex bg-slate-100 p-1 rounded-lg">
                    <button onClick={() => setViewMode('list')} className={`p-2 rounded-md ${viewMode === 'list' ? 'bg-white text-[#0f172a] shadow-sm' : 'text-slate-400'}`}><LayoutList size={20} /></button>
                    <button onClick={() => setViewMode('grid')} className={`p-2 rounded-md ${viewMode === 'grid' ? 'bg-white text-[#0f172a] shadow-sm' : 'text-slate-400'}`}><LayoutGrid size={20} /></button>
                    <button onClick={() => setViewMode('organogram')} className={`p-2 rounded-md ${viewMode === 'organogram' ? 'bg-white text-[#0f172a] shadow-sm' : 'text-slate-400'}`}><Workflow size={20} /></button>
                </div>
            </div>
          </header>
      </div>

      {/* VIEW CONTENT */}
      {viewMode === 'organogram' ? (
        <div className="flex-1 relative bg-[#f8fafc] overflow-hidden cursor-grab active:cursor-grabbing border-t border-slate-200 select-none">
            {/* Infinite Canvas */}
            <div 
                ref={canvasRef}
                className="absolute inset-0 w-full h-full"
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={handleMouseUp}
                onContextMenu={(e) => handleContextMenuCanvas(e, 'canvas')}
            >
                {/* Background Pattern (Dot Grid) */}
                <div 
                    className="absolute inset-0 pointer-events-none opacity-20"
                    style={{
                        backgroundImage: 'radial-gradient(#94a3b8 1px, transparent 1px)',
                        backgroundSize: `${20 * scale}px ${20 * scale}px`,
                        backgroundPosition: `${pan.x}px ${pan.y}px`
                    }}
                />

                <div 
                    className="absolute top-0 left-0 w-full h-full origin-top-left transition-transform duration-75 ease-linear"
                    style={{ transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})` }}
                >
                    {/* LAYER 0: SECTIONS (Background Areas) */}
                    {sections.map(section => {
                         const style = SECTION_COLORS.find(c => c.id === section.color) || SECTION_COLORS[0];
                         return (
                             <div
                                key={section.id}
                                className={`absolute border-2 border-dashed rounded-xl group/section ${style.bg} ${style.border}`}
                                style={{ left: section.x, top: section.y, width: section.width, height: section.height }}
                                onMouseDown={(e) => onDragStartEntity(e, 'section', section.id, section)}
                                onContextMenu={(e) => handleContextMenuCanvas(e, 'section', section.id)}
                             >
                                 <div className="absolute top-0 left-0 px-4 py-2 bg-white/50 rounded-br-xl backdrop-blur-sm border-r border-b border-inherit">
                                     <input 
                                        value={section.title}
                                        onChange={(e) => updateSection(section.id, 'title', e.target.value)}
                                        className="bg-transparent font-bold text-slate-500 text-xs uppercase tracking-wider outline-none w-32"
                                     />
                                 </div>
                                 {/* Resize Handle */}
                                 <div 
                                    className="absolute bottom-0 right-0 w-6 h-6 cursor-nwse-resize hover:bg-black/10 rounded-tl"
                                    onMouseDown={(e) => onDragStartEntity(e, 'resize-section', section.id, { x: 0, y: 0, width: section.width, height: section.height })}
                                 />
                             </div>
                         )
                    })}

                    {/* LAYER 1: CONNECTIONS */}
                    <svg className="absolute top-[-10000px] left-[-10000px] w-[20000px] h-[20000px] pointer-events-none overflow-visible">
                        <defs>
                            <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
                                <polygon points="0 0, 10 3.5, 0 7" fill="#94a3b8" />
                            </marker>
                        </defs>
                        {roles.map(role => {
                            if (!role.parentId) return null;
                            const parent = roles.find(r => r.id === role.parentId);
                            if (!parent) return null;
                            return (
                                <path 
                                    key={role.id}
                                    d={getSmartPath(parent, role)} 
                                    stroke="#94a3b8" strokeWidth="2" fill="none" markerEnd="url(#arrowhead)" 
                                />
                            );
                        })}
                        {connectingNodeId && (
                            <line 
                                x1={(() => {
                                    const r = roles.find(n => n.id === connectingNodeId);
                                    return (r?.x || 0) + 128; 
                                })()}
                                y1={(() => {
                                    const r = roles.find(n => n.id === connectingNodeId);
                                    return (r?.y || 0) + 80;
                                })()}
                                x2={mousePos.x}
                                y2={mousePos.y}
                                stroke="#fbbf24" strokeWidth="2" strokeDasharray="5,5"
                            />
                        )}
                    </svg>

                    {/* LAYER 2: DECORATIONS (Icons) */}
                    {decorations.map(deco => (
                        <div
                            key={deco.id}
                            className="absolute text-slate-400 hover:text-slate-600 transition-colors cursor-move"
                            style={{ left: deco.x, top: deco.y, transform: `scale(${deco.scale})` }}
                            onMouseDown={(e) => onDragStartEntity(e, 'decoration', deco.id, deco)}
                            onContextMenu={(e) => handleContextMenuCanvas(e, 'decoration', deco.id)}
                        >
                            {getDecorationIcon(deco.type)}
                            {deco.label && <div className="absolute top-full left-1/2 -translate-x-1/2 text-[10px] font-bold mt-1 bg-white px-1 rounded shadow-sm whitespace-nowrap">{deco.label}</div>}
                        </div>
                    ))}

                    {/* LAYER 3: ROLES (Cards) */}
                    {roles.map(role => {
                        const style = CARD_COLORS.find(c => c.id === (role.color || 'slate')) || CARD_COLORS[0];
                        const connectorStyle = "absolute w-4 h-4 bg-white border border-slate-300 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-crosshair hover:bg-blue-50 hover:border-blue-500 z-50";

                        return (
                            <div 
                                key={role.id}
                                className={`absolute w-64 bg-white rounded-lg shadow-sm border group hover:shadow-xl transition-shadow ${style.border} ${connectingNodeId === role.id ? 'ring-2 ring-[#fbbf24]' : ''}`}
                                style={{ left: role.x, top: role.y }}
                                onMouseDown={(e) => onDragStartEntity(e, 'role', role.id, role)}
                                onMouseUp={(e) => onConnectorMouseUp(e, role.id)}
                                onContextMenu={(e) => handleContextMenuCanvas(e, 'node', role.id)}
                            >
                                {/* Connectors (N/S/E/W) */}
                                <div className={`${connectorStyle} -top-2 left-1/2 -translate-x-1/2`} onMouseDown={(e) => { e.stopPropagation(); setConnectingNodeId(role.id); }} />
                                <div className={`${connectorStyle} -bottom-2 left-1/2 -translate-x-1/2`} onMouseDown={(e) => { e.stopPropagation(); setConnectingNodeId(role.id); }} />
                                <div className={`${connectorStyle} top-1/2 -left-2 -translate-y-1/2`} onMouseDown={(e) => { e.stopPropagation(); setConnectingNodeId(role.id); }} />
                                <div className={`${connectorStyle} top-1/2 -right-2 -translate-y-1/2`} onMouseDown={(e) => { e.stopPropagation(); setConnectingNodeId(role.id); }} />

                                {/* Header */}
                                <div className={`px-3 py-2 rounded-t-lg border-b flex justify-between items-center ${style.header} ${style.border}`}>
                                    <div className="flex items-center gap-2">
                                        <div className={`p-0.5 rounded ${style.text} bg-white/20`}>
                                            {role.category === 'Operational' ? <Briefcase size={12}/> : <CheckSquare size={12}/>}
                                        </div>
                                        <span className={`text-[10px] font-bold uppercase ${style.text}`}>{role.category === 'Operational' ? 'Operacional' : 'Admin'}</span>
                                    </div>
                                    <div className="flex gap-1">
                                         {role.additionalHazard && <span className="text-[9px] font-bold bg-orange-100 text-orange-700 px-1 rounded">INS</span>}
                                         {role.additionalDanger && <span className="text-[9px] font-bold bg-red-100 text-red-700 px-1 rounded">PER</span>}
                                    </div>
                                </div>

                                {/* Content */}
                                <div className="p-3">
                                    <input 
                                        value={role.title}
                                        onChange={(e) => updateRole(role.id, 'title', e.target.value)}
                                        className="w-full font-bold text-slate-800 text-sm bg-transparent border-none p-0 focus:ring-0 mb-2 placeholder-slate-400"
                                        placeholder="Nome do Cargo"
                                    />
                                    <div className="flex gap-2">
                                        <div className="flex-1 bg-slate-50 rounded border border-slate-100 px-2 py-1">
                                            <label className="text-[8px] font-bold text-slate-400 uppercase block">Salário Base</label>
                                            <input 
                                                value={(role.baseSalary * 100).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                                onChange={(e) => handleSalaryChange(role.id, e.target.value)}
                                                className="w-full bg-transparent text-xs font-bold text-slate-700 border-none p-0 focus:ring-0"
                                            />
                                        </div>
                                        <div className="w-16 bg-slate-50 rounded border border-slate-100 px-2 py-1 text-center">
                                            <label className="text-[8px] font-bold text-slate-400 uppercase block">Qtd</label>
                                            <input 
                                                type="number"
                                                value={role.quantity}
