                                <button onClick={() => { addDecoration('alert', contextMenu.x, contextMenu.y); setContextMenu(null); }} className="p-2 hover:bg-slate-100 rounded flex justify-center"><AlertTriangle size={20} className="text-amber-500"/></button>
