                             <tr key={role.id} className="hover:bg-slate-50 group">
                                 <td className="px-6 py-4">
                                     <input type="text" value={role.title} onChange={(e) => updateRole(role.id, 'title', e.target.value)} className="bg-transparent border-none font-bold text-slate-700 p-0 focus:ring-0 w-full" />
                                 </td>
                                 <td className="px-6 py-4">
                                     <span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-bold ${role.category === 'Operational' ? 'bg-blue-50 text-blue-700 border border-blue-100' : 'bg-slate-100 text-slate-600 border border-slate-200'}`}>
                                         {role.category === 'Operational' ? 'Operacional' : 'Admin'}
                                     </span>
                                 </td>
                                 <td className="px-6 py-4">
                                     <input type="number" value={role.quantity} onChange={(e) => updateRole(role.id, 'quantity', parseFloat(e.target.value))} className="w-full bg-slate-50 border border-slate-200 rounded text-center font-bold text-slate-700 py-1" />
                                 </td>
                                 <td className="px-6 py-4">
                                     <div className="flex items-center gap-1">
                                        <span className="text-slate-400 text-xs">R$</span>
                                        <input value={(role.baseSalary * 100).toLocaleString('pt-BR', { minimumFractionDigits: 2 })} onChange={(e) => handleSalaryChange(role.id, e.target.value)} className="w-full bg-transparent border-none font-bold text-slate-700 p-0 focus:ring-0" />
                                     </div>
                                 </td>
                                 <td className="px-6 py-4">
                                     <div className="flex gap-2">
                                         <button onClick={() => updateRole(role.id, 'additionalHazard', !role.additionalHazard)} className={`p-1 rounded border text-[10px] font-bold uppercase ${role.additionalHazard ? 'bg-orange-50 border-orange-200 text-orange-600' : 'bg-slate-50 border-slate-100 text-slate-300'}`}>INS (20%)</button>
                                         <button onClick={() => updateRole(role.id, 'additionalDanger', !role.additionalDanger)} className={`p-1 rounded border text-[10px] font-bold uppercase ${role.additionalDanger ? 'bg-red-50 border-red-200 text-red-600' : 'bg-slate-50 border-slate-100 text-slate-300'}`}>PER (30%)</button>
                                     </div>
                                 </td>
                                 <td className="px-6 py-4 text-right font-bold text-slate-700">{formatCurrency(calculateRoleCost(role))}</td>
                                 <td className="px-6 py-4 text-center">
                                     <button onClick={() => removeEntity('role', role.id)} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16} /></button>
                                 </td>
                             </tr>
                         ))}
                     </tbody>
                  </table>
                  <div className="p-4 bg-slate-50 border-t border-slate-200 flex gap-4">
                      <button onClick={() => addRole('Operational')} className="text-xs font-bold bg-white border border-slate-300 text-slate-600 px-4 py-2 rounded-lg hover:bg-blue-50 flex items-center gap-2"><Plus size={14} /> Adicionar Operacional</button>
                      <button onClick={() => addRole('Administrative')} className="text-xs font-bold bg-white border border-slate-300 text-slate-600 px-4 py-2 rounded-lg hover:bg-purple-50 flex items-center gap-2"><Plus size={14} /> Adicionar Administrativo</button>
                  </div>
               </div>
            )}

            {viewMode === 'grid' && (
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {roles.map(role => (
                        <div key={role.id} className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 relative group hover:shadow-md transition-shadow">
                             <div className="flex justify-between items-start mb-4">
                                 <div className={`p-2 rounded-lg ${role.category === 'Operational' ? 'bg-blue-50 text-blue-600' : 'bg-slate-100 text-slate-600'}`}>
                                     {role.category === 'Operational' ? <Briefcase size={20}/> : <CheckSquare size={20}/>}
                                 </div>
                                 <button onClick={() => removeEntity('role', role.id)} className="text-slate-300 hover:text-red-500 hover:bg-red-50 p-1.5 rounded transition-colors">
                                     <Trash2 size={16} />
                                 </button>
                             </div>

                             <input type="text" value={role.title} onChange={(e) => updateRole(role.id, 'title', e.target.value)} className="w-full text-lg font-bold text-slate-800 bg-transparent border-none p-0 focus:ring-0 mb-1"/>
                             <p className="text-xs text-slate-400 uppercase font-bold mb-4">{role.category === 'Operational' ? 'Operacional' : 'Administrativo'}</p>

                             <div className="space-y-3 bg-slate-50 p-4 rounded-lg border border-slate-100">
                                 <div className="flex justify-between items-center">
                                     <label className="text-xs font-bold text-slate-500">Salário Base</label>
                                     <div className="flex items-center gap-1 w-28">
                                         <span className="text-xs text-slate-400">R$</span>
                                         <input value={(role.baseSalary * 100).toLocaleString('pt-BR', { minimumFractionDigits: 2 })} onChange={(e) => handleSalaryChange(role.id, e.target.value)} className="w-full bg-transparent text-right font-bold text-slate-700 text-sm border-none p-0 focus:ring-0" />
                                     </div>
                                 </div>
                                 <div className="flex justify-between items-center">
                                     <label className="text-xs font-bold text-slate-500">Quantidade</label>
                                     <input type="number" value={role.quantity} onChange={(e) => updateRole(role.id, 'quantity', parseFloat(e.target.value))} className="w-16 bg-white border border-slate-200 text-center font-bold text-slate-700 text-sm rounded py-0.5 focus:ring-0" />
                                 </div>
                             </div>

                             <div className="mt-4 flex gap-2">
                                <button onClick={() => updateRole(role.id, 'additionalHazard', !role.additionalHazard)} className={`flex-1 py-2 rounded text-xs font-bold border transition-colors ${role.additionalHazard ? 'bg-orange-50 border-orange-200 text-orange-600' : 'bg-white border-slate-200 text-slate-400'}`}>Insalubridade</button>
                                <button onClick={() => updateRole(role.id, 'additionalDanger', !role.additionalDanger)} className={`flex-1 py-2 rounded text-xs font-bold border transition-colors ${role.additionalDanger ? 'bg-red-50 border-red-200 text-red-600' : 'bg-white border-slate-200 text-slate-400'}`}>Periculosidade</button>
                             </div>

                             <div className="mt-4 pt-4 border-t border-slate-100 flex justify-between items-center">
                                 <span className="text-xs font-bold text-slate-400 uppercase">Custo Total</span>
                                 <span className="text-lg font-black text-slate-800">{formatCurrency(calculateRoleCost(role))}</span>
                             </div>
                        </div>
                    ))}

                    <button onClick={() => addRole('Operational')} className="border-2 border-dashed border-slate-300 rounded-xl p-6 flex flex-col items-center justify-center text-slate-400 hover:border-blue-400 hover:text-blue-500 hover:bg-blue-50 transition-all min-h-[300px]">
                        <Plus size={32} className="mb-2" />
                        <span className="font-bold text-sm">Adicionar Cargo</span>
                    </button>
                </div>
            )}
          </div>
      )}
    </div>
  );
};

export default Team;

export interface Client {
  id: string;
  name: string;
  cnpj?: string;
  industry?: string;
  contactName?: string;
  email?: string; // Novo campo
  phone?: string; // Novo campo
  location?: string;
  status: 'Active' | 'Inactive';
}

export interface CanvasSection {
  id: string;
  title: string;
  x: number;
  y: number;
  width: number;
  height: number;
  color: string; // Hex color or class ID for background
}

export interface CanvasDecoration {
  id: string;
  type: 'factory' | 'tools' | 'truck' | 'user' | 'alert' | 'box';
  x: number;
  y: number;
  scale: number;
  label?: string;
}

export type ConnectionSide = 'top' | 'right' | 'bottom' | 'left';

export interface Role {
  id: string;
  parentId?: string; // ID do cargo supervisor (para Organograma)

  // Connection Preferences (Optional - for visual persistence if needed later)
  parentSourceSide?: ConnectionSide; 
  childTargetSide?: ConnectionSide;

  title: string;
  category: 'Operational' | 'Administrative';
  quantity: number;
  baseSalary: number;
  additionalHazard: boolean; // Insalubridade (20%)
  additionalDanger: boolean; // Periculosidade (30%)
  // Canvas Coordinates & Style
  x?: number;
  y?: number;
  color?: string; // Card header color
}

export interface ExpenseItem {
  id: string;
  name: string;
  category: 'EPI' | 'Tools' | 'Vehicles' | 'Consumables' | 'IT';
  unitPrice: number;
  lifespan: number; // In months
  allocation: 'Fixed' | 'PerHead';
}

// Novos Tipos para Segurança e Suporte
export interface SafetyItem {
  id: string;
  nrCode: string; // ex: 'NR-35'
  name: string;
  active: boolean;
  costPerHead: number; // Custo de Treinamento/Exame por pessoa
  frequencyMonths: number; // Validade do treinamento (ex: 24 meses)
}

export interface SupportItem {
  id: string;
  description: string; // ex: 'Visita Gestor Operacional'
  frequency: 'Weekly' | 'Biweekly' | 'Monthly' | 'Quarterly';
  costPerVisit: number;
  quantity: number; // Qtd de visitas no período
}

// --- NOVOS TIPOS PARA KITS PADRÃO ---
export interface KitItemTemplate {
    id: string;
    name: string;
    unitPrice: number;
    lifespan: number;
    category: ExpenseItem['category'];
}

export interface KitTemplate {
    id: string;
    name: string;
    icon: 'HardHat' | 'TrendingUp' | 'Wand2' | 'Package' | 'Wrench' | 'Truck' | 'Monitor';
    description: string;
    items: KitItemTemplate[];
}

export interface Attachment {
  id: string;
  name: string;
  size: string;
  type: string;
  uploadDate: string;
}

export interface ChargeComponent {
  id: string;
  name: string;
  value: number; // percentage (e.g. 0.20 for 20%)
}

export interface TaxItem {
  id: string;
  name: string;
  rate: number; // percentage
  active: boolean;
  type: 'SALES' | 'INCOME'; // SALES = Gross Up; INCOME = Profit Deduction
}

// --- CONFIGURAÇÃO CONTÁBIL (PLANO DE CONTAS) ---
export interface AccountingAccount {
    code: string; // ex: "3.1.01"
    name: string; // ex: "Receita Bruta de Serviços"
    type: 'CREDIT' | 'DEBIT';
}

export interface AccountingMapping {
    revenueAccount: AccountingAccount;
    deductionTaxesAccount: AccountingAccount; // Impostos s/ Venda
    directLaborAccount: AccountingAccount; // Salários
    laborChargesAccount: AccountingAccount; // Encargos
    laborProvisionsAccount: AccountingAccount; // Provisões (Férias/13o)
    operationalCostsAccount: AccountingAccount; // Materiais/EPIs
    safetyCostsAccount: AccountingAccount; // SMS
    supportCostsAccount: AccountingAccount; // Overhead
    marginAccount: AccountingAccount; // Lucro
    financialResultAccount: AccountingAccount; // Resultado Financeiro
}

export interface TaxConfig {
  regime: 'Lucro Real' | 'Lucro Presumido';
  calculationMode: 'NORMATIVE' | 'COMMERCIAL'; // NORMATIVE = Sales Tax only in Gross Up; COMMERCIAL = Sales + Income in Gross Up

  socialChargesRate: number;
  chargesBreakdown: {
    groupA: ChargeComponent[];
    groupB: ChargeComponent[];
    groupC: ChargeComponent[];
    groupD: ChargeComponent[];
  };

  salesTaxes: TaxItem[]; // PIS, COFINS, ISS, etc.
  incomeTaxes: TaxItem[]; // IRPJ, CSLL

  revenueTaxesRate: number; // Deprecated/Read-only sum
}

export interface ProposalDocuments {
  clientMemo: string; // O que o cliente pediu (informal)
  deliverables: string; // O que será entregue (formal)
  clientBudget?: number; // Target Price do cliente para Gap Analysis
  technicalAssumptions: string; // Premissas técnicas
  technicalNumber?: string; // Novo: Número da solicitação técnica
  attachments: Attachment[]; // Novo: Arquivos anexados
}

export type ProposalStatus = 'Draft' | 'Sent' | 'Negotiation' | 'Won' | 'Lost';

export type PricingModel = 'MARKUP' | 'MARGIN';

export interface ProposalData {
  id: string; // Internal UUID
  proposalId: string; // Human readable ID (e.g. 180256)
  version: number; // 1, 2, 3...
  createdAt: string;
  updatedAt: string;

  // New CRM Fields
  expirationDate: string; // Data de validade da proposta
  responsible: string; // Quem fez a precificação

  clientId?: string; // Link to Client Registry
  clientName: string; // Snapshot or fallback
  status: ProposalStatus;

  // CRM Data
  probability: number; // 0-100%
  value: number; // Snapshot of the total value

  // Pricing Data
  pricingModel?: PricingModel; // 'MARKUP' (Sobre Custo) ou 'MARGIN' (Sobre Venda/Numerador)
  markup: number; // Used for calculation (effective markup)
  targetMargin?: number; // Used for UI input when pricingModel === 'MARGIN'

  financialCostRate: number;
  contingencyRate: number;

  // --- PROJECT TIMELINE & FINANCE ---
  contractStartDate?: string; // Data de início do contrato (YYYY-MM-DD)
  mobilizationMonths: number; // Meses antes do início (ex: 1)
  contractDuration: number; // Padrão 12 meses

  paymentTermDays: number; // Prazo de recebimento (ex: 30, 45, 60)
  supplierPaymentTermDays: number; // Prazo médio pagto fornecedores
  payrollCashFlowDay: number; // Dia do mês para pagamento de folha (ex: 5)

  wacc: number; // Weighted Average Cost of Capital (TMA do Projeto) anual

  // --- LOCAL OVERRIDES ---
  issTaxOverride?: number; // Se definido, substitui a taxa de ISS global (ex: 0.02)

  roles: Role[];
  sections?: CanvasSection[]; // Background Areas/Lanes
  decorations?: CanvasDecoration[]; // Icons and visual elements

  expenses: ExpenseItem[];

  // Novos Arrays de Custo
  safetyCosts: SafetyItem[]; // NRs, Treinamentos
  supportCosts: SupportItem[]; // Overhead, Visitas de Gestão

  // Configuração de Kits (Geralmente preenchido apenas no GlobalConfig)
  kitTemplates?: KitTemplate[];

  taxConfig: TaxConfig;

  // Configuração Contábil Global (Injetada)
  accountingConfig?: AccountingMapping;

  // Documentation & Analysis
  documents: ProposalDocuments;
}

export interface CalculatedFinancials {
  totalLaborCost: number;
  totalOperationalCost: number; // Materiais e Despesas
  totalSafetyCost: number; // Novo: Treinamentos e Exames
  totalSupportCost: number; // Novo: Overhead de Gestão

  totalDirectCost: number; // Soma de tudo acima

  totalIndirectCost: number; // Financial + Contingency
  totalCostBase: number; // Direct + Indirect

  markupAmount: number; // Result. Operacional (Contábil Final)
  netRevenue: number; // Preço sem impostos
  grossRevenue: number; // Preço Final

  // --- NEW FIELDS ---
  contributionMarginAmount: number; // Margem Operacional (Net Revenue - Direct Costs)
  contributionMarginPercent: number; 

  operationalProfitAmount: number; // EBITDA (Contribution - Contingency/Overhead)
  operationalMarginPercent: number; // % da Margem Operacional sobre Venda Bruta

  salesTaxAmount: number; // Impostos da Nota
  incomeTaxAmount: number; // Estimativa de IRPJ/CSLL

  grossMarginPercent: number; // Margem Contábil
  netProfitAmount: number; // Resultado Líquido Final Estimado
  netProfitPercent: number; 

  monthlyValue: number;
  annualValue: number;
}

