            {/* CONTEXT MENU */}
            {contextMenu && (
                <div 
                    className="fixed z-[100] bg-white rounded-lg shadow-xl border border-slate-200 py-1 w-56 text-sm animate-in fade-in zoom-in-95 duration-100"
